__d(function(g,r,i,a,m,e,d){"use strict";Object.defineProperty(e,'__esModule',{value:!0}),Object.defineProperty(e,"attractions",{enumerable:!0,get:function(){return t}});const t=[{id:'attr-001',name:'Diriyah - At-Turaif District',nameAr:'\u0627\u0644\u062f\u0631\u0639\u064a\u0629 - \u062d\u064a \u0627\u0644\u0637\u0631\u064a\u0641',description:'A UNESCO World Heritage Site and the birthplace of the first Saudi state. The mud-brick ruins of At-Turaif palace district offer a fascinating glimpse into 18th-century Arabian architecture and governance. Ongoing restoration has transformed the area into a world-class cultural destination.',category:'heritage',images:['https://images.pexels.com/photos/28435066/pexels-photo-28435066.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/34919484/pexels-photo-34919484.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/13741445/pexels-photo-13741445.jpeg?auto=compress&cs=tinysrgb&w=800'],rating:4.7,reviewCount:3842,price:75,currency:'SAR',latitude:24.7343,longitude:46.5728,city:'Riyadh',openingHours:'9:00 AM - 9:00 PM',isFeatured:!0},{id:'attr-002',name:'Hegra (Mada\'in Saleh)',nameAr:'\u0627\u0644\u062d\u062c\u0631 (\u0645\u062f\u0627\u0626\u0646 \u0635\u0627\u0644\u062d)',description:'Saudi Arabia\'s first UNESCO World Heritage Site featuring over 100 monumental Nabataean tombs carved into sandstone outcrops. Often compared to Petra in Jordan, Hegra served as the southern capital of the Nabataean kingdom. The site spans 52 hectares in the AlUla desert landscape.',category:'heritage',images:['https://images.pexels.com/photos/18611226/pexels-photo-18611226.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/8333637/pexels-photo-8333637.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/50628/pexels-photo-50628.jpeg?auto=compress&cs=tinysrgb&w=800'],rating:4.9,reviewCount:5210,price:95,currency:'SAR',latitude:26.7868,longitude:37.9532,city:'AlUla',openingHours:'7:00 AM - 7:00 PM',isFeatured:!0},{id:'attr-003',name:'Jeddah Historic District (Al-Balad)',nameAr:'\u062c\u062f\u0629 \u0627\u0644\u062a\u0627\u0631\u064a\u062e\u064a\u0629 (\u0627\u0644\u0628\u0644\u062f)',description:'A UNESCO World Heritage Site showcasing traditional Hejazi architecture with ornate coral-stone buildings and iconic wooden Roshan balconies. The district served as a gateway for pilgrims traveling to Makkah for centuries. Wander narrow alleyways filled with souqs, heritage houses, and vibrant street art.',category:'heritage',images:['https://images.pexels.com/photos/17455023/pexels-photo-17455023.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/17285748/pexels-photo-17285748.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/32849341/pexels-photo-32849341.jpeg?auto=compress&cs=tinysrgb&w=800'],rating:4.5,reviewCount:4120,price:0,currency:'SAR',latitude:21.4858,longitude:39.1862,city:'Jeddah',openingHours:'Open 24 hours',isFeatured:!0},{id:'attr-004',name:'Rijal Almaa Heritage Village',nameAr:'\u0642\u0631\u064a\u0629 \u0631\u062c\u0627\u0644 \u0623\u0644\u0645\u0639 \u0627\u0644\u062a\u0631\u0627\u062b\u064a\u0629',description:'A stunning mountain village in the Asir region known for its colorful multi-story stone towers decorated with quartz and vibrant murals. Rijal Almaa has been nominated as a UNESCO World Heritage Site and offers insight into the unique culture of the southern highlands. The village museum houses over 2,800 artifacts.',category:'heritage',images:['https://images.pexels.com/photos/32918869/pexels-photo-32918869.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/22661905/pexels-photo-22661905.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/30812218/pexels-photo-30812218.jpeg?auto=compress&cs=tinysrgb&w=800'],rating:4.6,reviewCount:1890,price:20,currency:'SAR',latitude:19.0933,longitude:42.2817,city:'Rijal Almaa',openingHours:'8:00 AM - 6:00 PM',isFeatured:!1},{id:'attr-005',name:'Edge of the World (Jebel Fihrayn)',nameAr:'\u062d\u0627\u0641\u0629 \u0627\u0644\u0639\u0627\u0644\u0645 (\u062c\u0628\u0644 \u0641\u0647\u0631\u064a\u0646)',description:'A dramatic 300-meter cliff edge overlooking an endless expanse of ancient seabed in the Tuwaiq Escarpment northwest of Riyadh. The breathtaking panoramic views make it one of Saudi Arabia\'s most photographed natural landmarks. Accessible via a scenic desert drive, it is best visited during cooler months.',category:'nature',images:['https://images.pexels.com/photos/5863922/pexels-photo-5863922.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/9229412/pexels-photo-9229412.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/34275753/pexels-photo-34275753.jpeg?auto=compress&cs=tinysrgb&w=800'],rating:4.8,reviewCount:6340,price:0,currency:'SAR',latitude:24.8422,longitude:46.1751,city:'Riyadh',openingHours:'Open 24 hours',isFeatured:!0},{id:'attr-006',name:'Kingdom Centre Tower',nameAr:'\u0628\u0631\u062c \u0627\u0644\u0645\u0645\u0644\u0643\u0629',description:'The iconic 302-meter skyscraper dominating the Riyadh skyline with its distinctive inverted parabolic arch at the summit. The Sky Bridge observation deck offers 360-degree views of the sprawling capital city. The tower houses luxury shopping, the Four Seasons Hotel, and premium office space.',category:'modern',images:['https://images.pexels.com/photos/35761/pexels-photo-35761.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/15839821/pexels-photo-15839821.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/17285748/pexels-photo-17285748.jpeg?auto=compress&cs=tinysrgb&w=800'],rating:4.5,reviewCount:8920,price:69,currency:'SAR',latitude:24.7112,longitude:46.6745,city:'Riyadh',openingHours:'9:30 AM - 11:30 PM',isFeatured:!0},{id:'attr-007',name:'King Abdullah Financial District (KAFD)',nameAr:'\u0645\u0631\u0643\u0632 \u0627\u0644\u0645\u0644\u0643 \u0639\u0628\u062f\u0627\u0644\u0644\u0647 \u0627\u0644\u0645\u0627\u0644\u064a',description:'A futuristic mega-development spanning 1.6 million square meters in northern Riyadh featuring striking contemporary architecture. KAFD serves as the kingdom\'s financial hub with towers, conference centers, and landscaped plazas. The district includes the iconic KAFD Grand Mosque with its geometric design.',category:'modern',images:['https://images.pexels.com/photos/15839821/pexels-photo-15839821.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/35761/pexels-photo-35761.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/17455023/pexels-photo-17455023.jpeg?auto=compress&cs=tinysrgb&w=800'],rating:4.4,reviewCount:2150,price:0,currency:'SAR',latitude:24.7666,longitude:46.6396,city:'Riyadh',openingHours:'Open 24 hours',isFeatured:!1},{id:'attr-008',name:'NEOM - The Line',nameAr:'\u0646\u064a\u0648\u0645 - \u0630\u0627 \u0644\u0627\u064a\u0646',description:'A revolutionary 170-kilometer linear city being built in Tabuk Province as part of the NEOM mega-project. The Line aims to house 9 million residents in a structure just 200 meters wide with no cars and zero carbon emissions. Visitor experiences showcase the bold vision through immersive exhibitions.',category:'modern',images:['https://images.pexels.com/photos/5967950/pexels-photo-5967950.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/3760999/pexels-photo-3760999.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/17975653/pexels-photo-17975653.jpeg?auto=compress&cs=tinysrgb&w=800'],rating:4.3,reviewCount:980,price:150,currency:'SAR',latitude:27.95,longitude:35.5833,city:'Tabuk',openingHours:'10:00 AM - 8:00 PM',isFeatured:!0},{id:'attr-009',name:'King Fahd Fountain',nameAr:'\u0646\u0627\u0641\u0648\u0631\u0629 \u0627\u0644\u0645\u0644\u0643 \u0641\u0647\u062f',description:'The tallest fountain in the world, shooting water up to 312 meters into the air along the Jeddah Corniche. The fountain is best viewed at night when illuminated by over 500 spotlights creating a spectacular light show. It has been a beloved Jeddah landmark since its inauguration in 1985.',category:'modern',images:['https://images.pexels.com/photos/17285748/pexels-photo-17285748.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/17455023/pexels-photo-17455023.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/3760999/pexels-photo-3760999.jpeg?auto=compress&cs=tinysrgb&w=800'],rating:4.4,reviewCount:7650,price:0,currency:'SAR',latitude:21.4947,longitude:39.1503,city:'Jeddah',openingHours:'6:00 PM - 12:00 AM',isFeatured:!1},{id:'attr-010',name:'Rub\' al Khali (Empty Quarter)',nameAr:'\u0627\u0644\u0631\u0628\u0639 \u0627\u0644\u062e\u0627\u0644\u064a',description:'The largest contiguous sand desert in the world stretching across 650,000 square kilometers of the Arabian Peninsula. The towering red sand dunes reach heights of over 250 meters, creating an otherworldly landscape. Desert safari tours offer dune bashing, camel rides, and unforgettable stargazing under pristine dark skies.',category:'nature',images:['https://images.pexels.com/photos/34275753/pexels-photo-34275753.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/28829633/pexels-photo-28829633.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/235974/pexels-photo-235974.jpeg?auto=compress&cs=tinysrgb&w=800'],rating:4.7,reviewCount:2340,price:0,currency:'SAR',latitude:21,longitude:51,city:'Najran',openingHours:'Open 24 hours',isFeatured:!0},{id:'attr-011',name:'Farasan Islands',nameAr:'\u062c\u0632\u0631 \u0641\u0631\u0633\u0627\u0646',description:'A pristine archipelago of over 80 coral islands in the Red Sea off the coast of Jazan, renowned for incredible marine biodiversity. The islands feature mangrove forests, Ottoman-era ruins, and some of the best snorkeling and diving in Saudi Arabia. The Farasan gazelle and diverse bird species make it a nature lover\'s paradise.',category:'nature',images:['https://images.pexels.com/photos/3760999/pexels-photo-3760999.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/17100727/pexels-photo-17100727.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/5967950/pexels-photo-5967950.jpeg?auto=compress&cs=tinysrgb&w=800'],rating:4.6,reviewCount:1450,price:0,currency:'SAR',latitude:16.7,longitude:42.1167,city:'Jazan',openingHours:'Open 24 hours',isFeatured:!1},{id:'attr-012',name:'Al Wahbah Crater',nameAr:'\u0641\u0648\u0647\u0629 \u0627\u0644\u0648\u0639\u0628\u0629',description:'A massive volcanic crater 250 meters deep and 2 kilometers in diameter with a striking white sodium phosphate crystal floor. Located in the Hejaz region, the crater is believed to have formed from a phreatic steam explosion. The hike down to the crater floor takes about 45 minutes and rewards visitors with surreal landscapes.',category:'nature',images:['https://images.pexels.com/photos/9069745/pexels-photo-9069745.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/9229412/pexels-photo-9229412.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/33310385/pexels-photo-33310385.jpeg?auto=compress&cs=tinysrgb&w=800'],rating:4.5,reviewCount:2870,price:0,currency:'SAR',latitude:22.9069,longitude:41.1375,city:'Taif',openingHours:'Open 24 hours',isFeatured:!1},{id:'attr-013',name:'Wadi Lajab',nameAr:'\u0648\u0627\u062f\u064a \u0644\u062c\u0628',description:'A breathtaking narrow canyon in the Jizan Province with towering cliff walls rising over 300 meters on either side of a flowing stream. Lush vegetation and small waterfalls create an unexpected oasis in the arid Arabian landscape. The canyon is a popular hiking destination and one of Saudi Arabia\'s most dramatic natural wonders.',category:'nature',images:['https://images.pexels.com/photos/16038805/pexels-photo-16038805.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/18430363/pexels-photo-18430363.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/9246815/pexels-photo-9246815.jpeg?auto=compress&cs=tinysrgb&w=800'],rating:4.7,reviewCount:1980,price:0,currency:'SAR',latitude:17.6358,longitude:43.1186,city:'Jazan',openingHours:'Open 24 hours',isFeatured:!1},{id:'attr-014',name:'Al Soudah Peak',nameAr:'\u0627\u0644\u0633\u0648\u062f\u0629',description:'The highest point in Saudi Arabia at approximately 3,015 meters above sea level in the Asir Mountains near Abha. The cool mountain climate, terraced agriculture, and misty juniper forests make it a unique escape from the desert heat. A cable car offers stunning views over the Tihama plains far below.',category:'nature',images:['https://images.pexels.com/photos/15573506/pexels-photo-15573506.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/67058/pexels-photo-67058.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/2397630/pexels-photo-2397630.jpeg?auto=compress&cs=tinysrgb&w=800'],rating:4.6,reviewCount:3450,price:30,currency:'SAR',latitude:18.2536,longitude:42.3753,city:'Abha',openingHours:'8:00 AM - 10:00 PM',isFeatured:!0},{id:'attr-015',name:'Masjid al-Haram',nameAr:'\u0627\u0644\u0645\u0633\u062c\u062f \u0627\u0644\u062d\u0631\u0627\u0645',description:'The holiest mosque in Islam and the largest mosque in the world, surrounding the sacred Kaaba in the heart of Makkah. Millions of Muslims visit annually for Hajj and Umrah pilgrimages, making it the most visited site on Earth. The grand mosque can accommodate over 2 million worshippers during peak seasons.',category:'religious',images:['https://images.pexels.com/photos/34956781/pexels-photo-34956781.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/18274181/pexels-photo-18274181.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/14440333/pexels-photo-14440333.jpeg?auto=compress&cs=tinysrgb&w=800'],rating:5,reviewCount:52e3,price:0,currency:'SAR',latitude:21.4225,longitude:39.8262,city:'Makkah',openingHours:'Open 24 hours',isFeatured:!0},{id:'attr-016',name:'Masjid an-Nabawi (The Prophet\'s Mosque)',nameAr:'\u0627\u0644\u0645\u0633\u062c\u062f \u0627\u0644\u0646\u0628\u0648\u064a',description:'The second holiest mosque in Islam, originally built by Prophet Muhammad (PBUH) and located in the heart of Madinah. The mosque features the iconic Green Dome and can accommodate over 1 million worshippers. Its serene courtyards with retractable umbrellas provide shade during the intense summer heat.',category:'religious',images:['https://images.pexels.com/photos/6099936/pexels-photo-6099936.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/19509209/pexels-photo-19509209.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/33551691/pexels-photo-33551691.jpeg?auto=compress&cs=tinysrgb&w=800'],rating:5,reviewCount:48e3,price:0,currency:'SAR',latitude:24.4672,longitude:39.6112,city:'Madinah',openingHours:'Open 24 hours',isFeatured:!0},{id:'attr-017',name:'Quba Mosque',nameAr:'\u0645\u0633\u062c\u062f \u0642\u0628\u0627\u0621',description:'The first mosque ever built in Islam, founded by Prophet Muhammad (PBUH) upon his arrival in Madinah during the Hijra. Praying two rak\'ahs at Quba Mosque is equivalent to performing Umrah according to Islamic tradition. The mosque has been extensively expanded and renovated into a beautiful modern structure.',category:'religious',images:['https://images.pexels.com/photos/32386587/pexels-photo-32386587.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/10629632/pexels-photo-10629632.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/24285084/pexels-photo-24285084.jpeg?auto=compress&cs=tinysrgb&w=800'],rating:4.9,reviewCount:12500,price:0,currency:'SAR',latitude:24.44,longitude:39.6175,city:'Madinah',openingHours:'Open 24 hours',isFeatured:!1},{id:'attr-018',name:'Saudi National Museum',nameAr:'\u0627\u0644\u0645\u062a\u062d\u0641 \u0627\u0644\u0648\u0637\u0646\u064a \u0627\u0644\u0633\u0639\u0648\u062f\u064a',description:'The largest museum in the kingdom located in the King Abdulaziz Historical Center in central Riyadh. Its eight galleries span the full sweep of Arabian history from prehistoric times through the unification of Saudi Arabia. Interactive exhibits, rare artifacts, and immersive displays make it an essential cultural visit.',category:'museum',images:['https://images.pexels.com/photos/11516396/pexels-photo-11516396.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/69903/pexels-photo-69903.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/6043796/pexels-photo-6043796.jpeg?auto=compress&cs=tinysrgb&w=800'],rating:4.5,reviewCount:6780,price:10,currency:'SAR',latitude:24.6486,longitude:46.7108,city:'Riyadh',openingHours:'8:00 AM - 8:00 PM',isFeatured:!0},{id:'attr-019',name:'Ithra (King Abdulaziz Center for World Culture)',nameAr:'\u0625\u062b\u0631\u0627\u0621 (\u0645\u0631\u0643\u0632 \u0627\u0644\u0645\u0644\u0643 \u0639\u0628\u062f\u0627\u0644\u0639\u0632\u064a\u0632 \u0627\u0644\u062b\u0642\u0627\u0641\u064a \u0627\u0644\u0639\u0627\u0644\u0645\u064a)',description:'A striking landmark cultural center in Dhahran built by Saudi Aramco, designed to look like a stack of pebbles. Ithra houses a museum, cinema, library, theater, and exhibition halls promoting arts, knowledge, and creativity. It was named one of Time magazine\'s 100 Greatest Places in the World.',category:'museum',images:['https://images.pexels.com/photos/15839821/pexels-photo-15839821.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/11516396/pexels-photo-11516396.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/69903/pexels-photo-69903.jpeg?auto=compress&cs=tinysrgb&w=800'],rating:4.7,reviewCount:4560,price:0,currency:'SAR',latitude:26.3092,longitude:50.1328,city:'Dhahran',openingHours:'9:00 AM - 9:00 PM',isFeatured:!0},{id:'attr-020',name:'Masmak Fortress',nameAr:'\u0642\u0635\u0631 \u0627\u0644\u0645\u0635\u0645\u0643',description:'A clay and mud-brick fort in the heart of old Riyadh where King Abdulaziz recaptured the city in 1902, marking the beginning of modern Saudi Arabia. The fortress now serves as a museum with displays of maps, photographs, and artifacts from the unification era. Visitors can still see the spearhead lodged in the main gate from the historic battle.',category:'museum',images:['https://images.pexels.com/photos/28435066/pexels-photo-28435066.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/34919484/pexels-photo-34919484.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/6043796/pexels-photo-6043796.jpeg?auto=compress&cs=tinysrgb&w=800'],rating:4.4,reviewCount:5890,price:0,currency:'SAR',latitude:24.6311,longitude:46.7136,city:'Riyadh',openingHours:'8:00 AM - 12:00 PM, 4:00 PM - 9:00 PM',isFeatured:!1},{id:'attr-021',name:'Elephant Rock (Jabal AlFil)',nameAr:'\u0635\u062e\u0631\u0629 \u0627\u0644\u0641\u064a\u0644 (\u062c\u0628\u0644 \u0627\u0644\u0641\u064a\u0644)',description:'A stunning natural sandstone formation in AlUla that remarkably resembles an elephant with its trunk reaching to the ground. Millions of years of wind and water erosion sculpted this geological marvel standing over 50 meters tall. The site is especially magical at sunset when the rock glows in warm amber tones.',category:'nature',images:['https://images.pexels.com/photos/18611226/pexels-photo-18611226.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/50628/pexels-photo-50628.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/8333637/pexels-photo-8333637.jpeg?auto=compress&cs=tinysrgb&w=800'],rating:4.8,reviewCount:3670,price:50,currency:'SAR',latitude:26.8342,longitude:37.9119,city:'AlUla',openingHours:'6:00 AM - 10:00 PM',isFeatured:!0},{id:'attr-022',name:'Jeddah Tower (Under Construction)',nameAr:'\u0628\u0631\u062c \u062c\u062f\u0629 (\u062a\u062d\u062a \u0627\u0644\u0625\u0646\u0634\u0627\u0621)',description:'Set to become the world\'s tallest building at over 1,000 meters upon completion, Jeddah Tower is the centerpiece of the Jeddah Economic City development. The sleek triangular design by Adrian Smith draws inspiration from desert plant shoots. Visitors can view the construction progress from designated observation areas.',category:'modern',images:['https://images.pexels.com/photos/15839821/pexels-photo-15839821.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/35761/pexels-photo-35761.jpeg?auto=compress&cs=tinysrgb&w=800','https://images.pexels.com/photos/17285748/pexels-photo-17285748.jpeg?auto=compress&cs=tinysrgb&w=800'],rating:4,reviewCount:890,price:0,currency:'SAR',latitude:21.7235,longitude:39.2428,city:'Jeddah',openingHours:'Not yet open to public',isFeatured:!1}]},1027,[]);
